sp_rectangle_menu_item.record_script:
var bannerAwaitingExtensionApproval = function(data){
  var u = gs.getUser().getID();
  var filter = 'active=true^extension_requested=true^u_task_requesterDYNAMIC90d1921e5f510100a9ad2572f2b477fe' +
							'^NQactive=true^extension_requested=true^parentISEMPTY^primary_officeISNOTEMPTY^primary_office.tasking_authoritiesCONTAINSjavascript:gs.getUserID()' +
							'^NQactive=true^extension_requested=true^parentISNOTEMPTY^parent.ref_x_153465_discovert_route_task_instance.primary_assigneeISNOTEMPTY^parent.ref_x_153465_discovert_route_task_instance.primary_assignee.tasking_authoritiesCONTAINSjavascript:gs.getUserID()' +
							'^NQactive=true^extension_requested=true^parentISNOTEMPTY^parent.ref_x_153465_discovert_route_task_instance.u_task_requesterDYNAMIC90d1921e5f510100a9ad2572f2b477fe';

  var tbf = new TaskerBannerFilters();

  tbf.label = 'Awaiting Extension Approval';
  tbf.table = 'x_153465_discovert_route_task_instance';
  tbf.filter = filter;
  tbf.orderDesc = 'sys_updated_on';
  tbf.idField = 'sys_id';
  tbf.displayFieldName = 'task_name';
	// STRY0116257 - set to blank so default is picked up from system settings
  tbf.linkView = '';
	tbf.pageId = '';
  tbf.viewAllLinkTitle = gs.getMessage('View all requests');
  tbf.viewAllLinkPageId = 'discovertasker_detailsdrilldown';
  tbf.viewAllLinkView = 'sp';
  tbf.viewAllLinkFilter = filter;

  tbf.createBanner();
  data.items = tbf.items;
  data.record_watchers = tbf.record_watchers;
  data.count = tbf.count;

}

bannerAwaitingExtensionApproval(data);
